import pytest

def reverse_words(s: str) -> str:
    return ' '.join(s.split()[::-1])

class TestReverseWords:
    def test_happy_path(self):
        assert reverse_words("the sky is blue") == "blue is sky the"

    def test_single_word(self):
        assert reverse_words("hello") == "hello"

    def test_empty_string(self):
        assert reverse_words("") == ""

    def test_leading_and_trailing_spaces(self):
        assert reverse_words("  the sky is blue  ") == "blue is sky the"

    def test_multiple_spaces_between_words(self):
        assert reverse_words("the   sky   is blue") == "blue is sky the"

    def test_only_spaces(self):
        assert reverse_words("   ") == ""

    def test_string_with_numbers(self):
        assert reverse_words("1 2 3 4 5") == "5 4 3 2 1"

    def test_string_with_special_characters(self):
        assert reverse_words("!@# $%^ &*()") == "&*() $%^ !@#"

    def test_string_with_mixed_case(self):
        assert reverse_words("The Sky Is Blue") == "Blue Is Sky The"

    def test_string_with_unicode_characters(self):
        assert reverse_words("你好 世界") == "世界 你好"

    def test_long_string(self):
        long_string = "a " * 1000 + "b"
        expected_result = "b " + "a " * 1000
        assert reverse_words(long_string) == expected_result.strip()
